INSERT INTO "companies" ("id", "user_id", "name", "slug", "description", "industry", "website", "logo_url", "branding", "timezone", "settings", "is_active", "created_at", "updated_at", "chatwoot_account_id", "chatwoot_api_key", "chatwoot_data", "chatwoot_provisioned", "chatwoot_provisioned_at", "chatwoot_inbox_id", "client_type", "assistant_name", "deleted_at") VALUES ('1', '1', 'WITHMIA', 'withmia-evp7rj', 'Startup chilena innovadora que ofrece una solución SaaS diseñada específicamente para pequeñas y medianas empresas de Latinoamérica. Nuestra plataforma aborda la fragmentación operativa y potencia la productividad mediante un modelo de Lenguaje de Aprendizaje Automático (LLM) autoadministrable, empoderando a las PYMEs para alcanzar su máximo potencial.', NULL, 'https://withmia.com/', 'data:image/jpeg;base64,', NULL, 'America/Santiago', '{"onboarding":{"tools":["whatsapp","instagram","website","messenger","shopify","woocommerce","api","crm","reservo","calendar","excel","mercadolibre","drive","dropbox"],"client_type":"externo","has_website":true,"other_tools":"","discovered_via":[],"discovered_other":"","found_via_search":true,"monthly_conversations":"4900"},"qdrant_collection":"company_withmia-evp7rj_knowledge","training_webhook_url":"https:\/\/n8n-production-00dd.up.railway.app\/webhook\/training-withmia-evp7rj","training_workflow_id":"7kXlXYVJpttnGJaC","training_webhook_path":"training-withmia-evp7rj","training_workflow_name":"Training Chat - withmia-evp7rj","rag_workflow_id":"zDqy6hoBbUv5YVyI","rag_webhook_path":"rag-withmia-evp7rj","rag_workflow_name":"RAG Documents - withmia-evp7rj"}', '1', '2026-01-27 18:43:20', '2026-02-12 09:51:08', '1', 'LsgCRFINz50YWZ9PrNDQj2Be', '{"channel_token": "Fb2fsq7TvzAVx2TXMxKts6in", "channel_id": 1}', '1', '2026-01-27 18:45:22', '1', 'externo', 'Ana', NULL);
INSERT INTO "companies" ("id", "user_id", "name", "slug", "description", "industry", "website", "logo_url", "branding", "timezone", "settings", "is_active", "created_at", "updated_at", "chatwoot_account_id", "chatwoot_api_key", "chatwoot_data", "chatwoot_provisioned", "chatwoot_provisioned_at", "chatwoot_inbox_id", "client_type", "assistant_name", "deleted_at") VALUES ('13', '9', 'Broncopulmonar Citamédica', 'yarger-suarez', 'Especialidad en Broncopulmonar y Respiratoria: Comprometidos con la salud pulmonar, ofrecemos atención integral y especializada en enfermedades respiratorias, proporcionando diagnósticos precisos y tratamientos innovadores para mejorar la calidad de vida de nuestros pacientes.', 'salud', 'https://broncopulmonar.citamedica.cl', NULL, NULL, 'America/Santiago', '{"qdrant_collection":"company_yarger-suarez_knowledge","rag_workflow_id":"0Wv4rvx3YFBWwo9I","rag_webhook_path":"rag-yarger-suarez-aa953069","rag_webhook_url":"https:\/\/n8n-production-00dd.up.railway.app\/webhook\/rag-yarger-suarez-aa953069","rag_workflow_name":"RAG Documents - yarger-suarez","training_workflow_id":"KTdlRFXhfuPWKd7i","training_webhook_path":"training-yarger-suarez","training_webhook_url":"https:\/\/n8n-production-00dd.up.railway.app\/webhook\/training-yarger-suarez","training_workflow_name":"Training Chat - yarger-suarez"}', '1', '2026-02-13 10:40:33', '2026-02-13 10:40:38', '4', 'MXDQY0EiE18HtOgQGDVVemg5', '{"channel_token":"4wghGzYai2kS2liwiSobxsvV","channel_id":4}', '1', '2026-02-13 10:40:38', '4', 'externo', NULL, NULL);
INSERT INTO "failed_jobs" ("id", "uuid", "connection", "queue", "payload", "exception", "failed_at") VALUES ('1', '9b2cb98b-76dc-4da7-8506-99cd6ff7a958', 'database', 'high', '{"uuid":"9b2cb98b-76dc-4da7-8506-99cd6ff7a958","displayName":"App\\Jobs\\ProcessRagDocumentJob","job":"Illuminate\\Queue\\CallQueuedHandler@call","maxTries":3,"maxExceptions":null,"failOnTimeout":false,"backoff":"10","timeout":180,"retryUntil":null,"data":{"commandName":"App\\Jobs\\ProcessRagDocumentJob","command":"O:30:\"App\\Jobs\\ProcessRagDocumentJob\":4:{s:42:\"\u0000App\\Jobs\\ProcessRagDocumentJob\u0000webhookUrl\";s:27:\"\/webhook\/rag-withmia-evp7rj\";s:39:\"\u0000App\\Jobs\\ProcessRagDocumentJob\u0000payload\";a:7:{s:12:\"company_slug\";s:14:\"withmia-evp7rj\";s:8:\"category\";s:8:\"producto\";s:8:\"filename\";s:12:\"WITHMIA.docx\";s:4:\"text\";s:3146:\"1. Estructura de Planes (Suscripción Mensual SaaS)WITHMIA utiliza un modelo de suscripción escalonada alineada con la madurez digital y el volumen de usuarios del cliente.Plan Único (Básico)Precio: $18 USD mensuales.Precio Ref. (CLP): ~$17.000 CLP (Tasa de cambio: $950 CLP\/USD).Usuarios Incluidos: 1 usuario.Propósito: Actuar como precio psicológico de entrada para microempresas, diseñado para la adquisición masiva y la reducción del Costo de Adquisición (CAC).Alcance Técnico: Cubre el costo variable de infraestructura en AWS y el uso de la API de Meta.Plan Dual (Pro)Precio: $36 USD mensuales.Precio Ref. (CLP): ~$34.000 CLP.Usuarios Incluidos: 2 usuarios.Propósito: Dirigido al segmento Retail PYME (el de mayor volumen), permitiendo un flujo de caja que financia el soporte técnico y el desarrollo constante.Alcance Técnico: Incluye todas las funciones del plan básico con capacidad para equipos pequeños.Plan Grupal (Enterprise)Precio: $54 USD mensuales.Precio Ref. (CLP): ~$51.000 CLP.Usuarios Incluidos: 3 o más usuarios (enfocado en equipos de ventas corporativos).Propósito: Maximizar el ingreso por usuario (ARPU) en sectores como clínicas o servicios profesionales.Alcance Técnico: Incluye funciones avanzadas de Agenda y Cobros automatizados, justificando el ticket por el ahorro directo en horas-hombre.2. Componentes Transaccionales y PruebasAdemás de la suscripción fija, el bot debe conocer estos cobros y beneficios variables:Comisión por Éxito: Se aplica una comisión variable del 1% sobre transacciones de cobro exitosas realizadas a través de la plataforma. Esto alinea los ingresos de WITHMIA con el éxito del cliente.Período de Prueba (Free Trial): Todos los planes incluyen una prueba gratuita de 7 días para mitigar el riesgo percibido y facilitar la conversión.Activación Inmediata: Una vez confirmado el pago, el sistema instancia el entorno del cliente automáticamente en menos de 30 segundos.3. Justificación del Precio (Atributos de Valor)Para el entrenamiento del bot, es vital que sepa defender el precio frente a la competencia:AtributoDetalle para el BotCosto-BeneficioEl costo diario del Plan Único es de aprox. $0.6 USD, lo cual es inferior al costo de oportunidad de una hora de trabajo manual del dueño.ComparativaLa competencia corporativa (como Cliengo) parte desde los $45 USD, mientras que WITHMIA ofrece profundidad operativa (agendas\/stock) por $18 USD.Integración ProfundaA diferencia de bots baratos (&lt; $10 USD) que solo chatean, WITHMIA se integra nativamente con WooCommerce, Google Calendar y Pasarelas de Pago.4. Datos Técnicos para Integración (Backend)Si el bot necesita manejar lógica de base de datos o APIs:Middleware: La plataforma actúa como un orquestador que conecta canales (WhatsApp, Instagram, Web) con herramientas de negocio.Infraestructura: Todo corre sobre arquitectura Serverless (AWS Lambda), lo que permite que el costo de servidor por cliente sea marginal (aprox. $2.00 USD).Soberanía de Datos: La base de datos de clientes e historial reside en servidores propios en AWS, no en la infraestructura del proveedor del canal (Meta).\";s:14:\"openai_api_key\";s:164:\"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\";s:11:\"qdrant_host\";s:35:\"http:\/\/qdrant.railway.internal:6333\";s:14:\"qdrant_api_key\";s:34:\"qdrant_api_key_withmia_2024_secure\";}s:40:\"\u0000App\\Jobs\\ProcessRagDocumentJob\u0000filename\";s:12:\"WITHMIA.docx\";s:5:\"queue\";s:4:\"high\";}"},"createdAt":1770838126,"delay":null}', 'GuzzleHttp\Exception\ConnectException: cURL error 6: Could not resolve host: webhook (see https://curl.haxx.se/libcurl/c/libcurl-errors.html) for webhook/rag-withmia-evp7rj in /app/vendor/guzzlehttp/guzzle/src/Handler/CurlFactory.php:277
